def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for x in range(8, 0, -1):
                for y in range(1, x + 5):
                    for z in range(1, y + 3):
                        factor = ((ratio - x) ** 6) / ((x + y + z) * 1.1 + 1)
                        priority += factor * np.sin(ratio * (y + z) / (x + 1))
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 2
        elif 5 < ratio <= 8:
            for p in range(1, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 4):
                    for r in range(1, q + 2):
                        term = ((ratio - p) ** 4) * np.cos(ratio * p * r) / (q + r + 0.7)
                        priority += np.tanh(term) * 1.7
            priority += np.log(ratio) * 15 - np.tanh(ratio - 5) * 3
        elif 2 <= ratio <= 5:
            s = 0
            for m in range(1, 16):
                for n in range(1, m + 3):
                    s += ((ratio - 2) ** m) / (m * n * 2.1) * np.sin(m * n * ratio)
            priority = (s * np.cos(9 * ratio)) - np.log(ratio) * 8 + np.tanh(5 * (5 - ratio)) * 2.5
        elif 1 <= ratio < 2:
            s = 0
            for a in range(1, 12):
                for b in range(1, a + 2):
                    s += ((2 - ratio) ** a) / (a**2 + b + 0.3) * np.sin(a * b * ratio * 0.9)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3.2
            priority = s + penalty + np.exp(-2 / (ratio + 0.07))
            for c in range(1, 7):
                priority += np.sin(c * ratio * i * 1.3) * ((ratio - 1) ** c) / c
        elif 0.5 <= ratio < 1:
            s = 0
            for d in range(1, 20):
                s += ((1 - ratio) ** d) / (d * 5) * np.cos(d * ratio * 2.3)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for e in range(1, 8):
                priority += ((1 - ratio) ** e) * np.sin(e * item * 1.6) * 1.1
        elif 0.15 <= ratio < 0.5:
            s = 0
            for f in range(1, 15):
                s += ((0.5 - ratio) ** f) / (f * 4.5) * np.cos(f * ratio * 2.8)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.7) % 5 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.8) * 4
            for g in range(1, 10):
                priority += ((0.5 - ratio) ** g) / (g * 7.5) * np.cos(item * g * 1.4)
        else:
            s = 0
            for h in range(1, 12):
                for j in range(1, h + 3):
                    s += ((0.15 - ratio) ** h) / (h * j * 6) * np.sin(h * item * j * 1.05)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 3) * 5
            for k in range(1, 10):
                priority += ((0.15 - ratio) ** k) / (k * 9) * np.cos(item * k * 0.95)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 6
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.5
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.5
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.8
        priorities[i] = priority
    return priorities
